+/// Deploy binary to a single worker.
+async fn deploy_binary_to_worker(
+    worker: &WorkerConfig,
+    local_binary: &Path,
+    local_version: &str,
+    force: bool,
+    dry_run: bool,
+    ctx: &OutputContext,
+) -> DeployResult {
+    let style = ctx.theme();
+
+    if !ctx.is_json() {
+        print!(
+            "  {} {}@{} ... ",
+            StatusIndicator::Info.display(style),
+            style.highlight(&worker.user),
+            style.highlight(&worker.host)
+        );
+    }
+
+    // Check remote version
+    let remote_version = match get_remote_version(worker).await {
+        Ok(v) => Some(v),
+        Err(_) => None,
+    };
+
+    // Determine if we need to deploy
+    let needs_deploy = if force {
+        true
+    } else if let Some(ref rv) = remote_version {
+        major_version_mismatch(local_version, rv) || rv != local_version
+    } else {
+        true // Not installed
+    };
+
+    if !needs_deploy {
+        if !ctx.is_json() {
+            println!(
+                "{} (already at {})",
+                style.success("OK"),
+                style.muted(remote_version.as_deref().unwrap_or("?"))
+            );
+        }
+        return DeployResult {
+            worker_id: worker.id.to_string(),
+            success: true,
+            deployed: false,
+            local_version: local_version.to_string(),
+            remote_version,
+            error: None,
+        };
+    }
+
+    if dry_run {
+        if !ctx.is_json() {
+            println!(
+                "{} (would deploy {} → {})",
+                style.info("DRY-RUN"),
+                style.muted(remote_version.as_deref().unwrap_or("none")),
+                style.highlight(local_version)
+            );
+        }
+        return DeployResult {
+            worker_id: worker.id.to_string(),
+            success: true,
+            deployed: false,
+            local_version: local_version.to_string(),
+            remote_version,
+            error: Some("dry-run".to_string()),
+        };
+    }
+
+    // Deploy via SCP
+    match deploy_via_scp(worker, local_binary).await {
+        Ok(remote_path) => {
+            if !ctx.is_json() {
+                println!(
+                    "{} (deployed to {})",
+                    style.success("OK"),
+                    style.muted(&remote_path)
+                );
+            }
+            DeployResult {
+                worker_id: worker.id.to_string(),
+                success: true,
+                deployed: true,
+                local_version: local_version.to_string(),
+                remote_version: Some(local_version.to_string()),
+                error: None,
+            }
+        }
+        Err(e) => {
+            if !ctx.is_json() {
+                println!("{}", style.error(&format!("FAILED: {}", e)));
+            }
+            DeployResult {
+                worker_id: worker.id.to_string(),
+                success: false,
+                deployed: false,
+                local_version: local_version.to_string(),
+                remote_version,
+                error: Some(e.to_string()),
+            }
+        }
+    }
+}
